import itertools

def are_isomorphic(graph1, graph2):
    n1 = len(graph1)
    n2 = len(graph2)

    if n1 != n2:
        return False

    vertices = list(range(n1))

    for p in itertools.permutations(vertices):
        is_current_permutation_isomorphism = True

        for u in vertices:
            for v in vertices:
                u_connected_to_v_in_g1 = v in graph1.get(u, [])

                mapped_u = p[u]
                mapped_v = p[v]

                mapped_u_connected_to_mapped_v_in_g2 = mapped_v in graph2.get(mapped_u, [])

                if u_connected_to_v_in_g1 != mapped_u_connected_to_mapped_v_in_g2:
                    is_current_permutation_isomorphism = False
                    break
            if not is_current_permutation_isomorphism:
                break

        if is_current_permutation_isomorphism:
            return True

    return False
